// Creators API: OAuth2 client-credentials → short-lived access token (~1h). No refresh token.
const cfg = $('Config').first().json;
const credId     = String(cfg.creatorsCredentialId || '').trim();
const credSecret = String(cfg.creatorsCredentialSecret || '').trim();
const scope      = cfg.creatorsScope || 'creatorsapi::default';
const tokenHost  = cfg.creatorsTokenHost || 'api.amazon.com';
if (!credId || !credSecret || /YOUR_/.test(credId) || /YOUR_/.test(credSecret)) {
  throw new Error('Creators API config missing: set creatorsCredentialId and creatorsCredentialSecret in the Config node (created in Associates Central → Tools → Creators API).');
}
const enc = encodeURIComponent;
const form = `grant_type=client_credentials&scope=${enc(scope)}&client_id=${enc(credId)}&client_secret=${enc(credSecret)}`;
let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://${tokenHost}/auth/o2/token`,
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Accept': 'application/json' },
    body: form,
    returnFullResponse: true,
    timeout: 30000,
  });
} catch (err) {
  const r = (err && err.response) || (err && err.cause && err.cause.response) || {};
  const b = (r.data !== undefined) ? r.data : (r.body !== undefined ? r.body : (err.message || String(err)));
  const txt = (typeof b === 'string') ? b : JSON.stringify(b);
  const st = r.status || r.statusCode || ((String((err && err.message) || '').match(/status code (\d{3})/i) || [])[1]) || '?';
  throw new Error(`Creators token request failed (HTTP ${st}): ${txt.slice(0,300)}. Causes: invalid_client (wrong Credential ID/Secret), invalid_scope, or unauthorized_client (account not approved for the Creators API). If it's a content-type/400 error, the token endpoint may want a JSON body instead of form-encoded.`);
}
let data = resp.body;
if (typeof data === 'string') { try { data = JSON.parse(data); } catch (e) { data = {}; } }
const accessToken = data && data.access_token;
if (!accessToken) throw new Error(`Creators token response had no access_token: ${JSON.stringify(data).slice(0,300)}`);
console.log(JSON.stringify({ event: 'creators_token', expiresIn: data.expires_in, ts: new Date().toISOString() }));
return [{ json: { accessToken } }];

// Creators API: searchItems by keywords. ONE call returns price + images + ratings.
const cfg = $('Config').first().json;
const accessToken = $input.first().json.accessToken;
const host        = cfg.creatorsHost || 'creatorsapi.amazon';
const marketplace = cfg.creatorsMarketplace || 'www.amazon.com';
const kw          = String(cfg.creatorsKeywords || '').trim();
const itemCount   = Math.max(1, Math.min(10, Number(cfg.creatorsItemCount) || 10));
const partnerTag  = String(cfg.amazonAffiliateTag || '').trim();
if (!accessToken) throw new Error('No Creators access token from Get Creators Token.');
if (!kw) throw new Error('creatorsKeywords is empty in Config.');
if (!partnerTag) throw new Error('amazonAffiliateTag (partnerTag) is empty in Config.');

const requestBody = {
  keywords: kw,
  partnerTag,
  partnerType: 'Associates',
  itemCount,
  resources: [
    'itemInfo.title','itemInfo.byLineInfo','itemInfo.features',
    'offersV2.listings.price','offersV2.listings.savingBasis',
    'images.primary.large','browseNodeInfo.browseNodes',
    'customerReviews.count','customerReviews.starRating'
  ],
};

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://${host}/catalog/v1/searchItems`,
    headers: {
      'Authorization': `Bearer ${accessToken}`,
      'x-marketplace': marketplace,
      'Content-Type': 'application/json; charset=utf-8',
      'Accept': 'application/json',
    },
    body: requestBody,
    json: true,
    returnFullResponse: true,
    timeout: 60000,
  });
} catch (err) {
  const r = (err && err.response) || (err && err.cause && err.cause.response) || {};
  const b = (r.data !== undefined) ? r.data : (r.body !== undefined ? r.body : (err.message || String(err)));
  const txt = (typeof b === 'string') ? b : JSON.stringify(b);
  const st = r.status || r.statusCode || ((String((err && err.message) || '').match(/status code (\d{3})/i) || [])[1]) || '?';
  throw new Error(`Creators searchItems failed (HTTP ${st}): ${txt.slice(0,400)} | 401/403 = token scope or account not approved (need approved Creators account + ≥10 qualifying sales / 30 days); 400 = bad body/resources; also verify creatorsHost (${host}) and x-marketplace (${marketplace}).`);
}
let data = resp.body;
if (typeof data === 'string') { try { data = JSON.parse(data); } catch (e) { data = {}; } }
if (data && Array.isArray(data.errors) && data.errors.length) {
  const e = data.errors[0];
  throw new Error(`Creators API error ${e.code || ''}: ${e.message || JSON.stringify(data.errors).slice(0,300)}`);
}
const items = (data && data.searchResult && Array.isArray(data.searchResult.items)) ? data.searchResult.items
            : (Array.isArray(data.items) ? data.items : []);
console.log(JSON.stringify({ event: 'creators_searched', count: items.length, ts: new Date().toISOString() }));
return [{ json: { items } }];

// Creators API: emit one { asin, item } per product (item already carries price/images/ratings).
const cfg = $('Config').first().json;
const inp = $input.first().json;
const items = Array.isArray(inp.items) ? inp.items : [];

if (!items.length) {
  throw new Error('Creators API returned 0 items. Check creatorsKeywords / creatorsMarketplace and that the Creators account is approved.');
}

const cap = Math.max(1, Number(cfg.maxDealsPerRun) || 10);
const out = items.slice(0, cap).map((item) => ({ json: { asin: item && item.asin, item } }));
console.log(JSON.stringify({ event: 'creators_items_extracted', count: out.length, ts: new Date().toISOString() }));
return out;

// ─────────────────────────────────────────────────────────────────────────────
// Normalise (Creators API v1) — map a Creators API searchItems item → product shape.
// Output json/product shape is IDENTICAL to prior versions, so downstream is unchanged.
// Creators mirrors PA-API in lowerCamelCase; price/images/RATINGS come from the search item.
// Field paths are defensive (official schema is login-gated); keeps first-valid-price fallback.
// ─────────────────────────────────────────────────────────────────────────────
const cfg  = $('Config').first().json;
const loop = $('Loop Over Items').first().json;
const asin = loop.asin;
const item = loop.item || ($input.first().json && $input.first().json.item) || $input.first().json;

const fail = (reason) => [{ json: { valid: false, skipReason: reason, asin } }];

if (!asin || typeof asin !== 'string') return fail('missing ASIN');
if (!item || typeof item !== 'object') return fail('no Creators item object');

// ── Affiliate tag + clean tagless URL ─────────────────────────────────────────
const AFFILIATE_TAG_RE = /^[a-zA-Z0-9][a-zA-Z0-9-]*-\d{2}$/;
const affiliateTag = cfg.amazonAffiliateTag ? String(cfg.amazonAffiliateTag).trim() : '';
if (!affiliateTag || !AFFILIATE_TAG_RE.test(affiliateTag)) return fail(`amazonAffiliateTag invalid: "${cfg.amazonAffiliateTag}"`);

const AMAZON_DP_RE = /^https:\/\/(?:www\.)?amazon\.[a-z.]{2,10}\/dp\/([A-Z0-9]{10})(?:[\/?#].*)?$/;
const affiliateUrl = `https://www.amazon.com/dp/${asin}`;   // clean, tagless (tag re-appended at render)
if (!AMAZON_DP_RE.test(affiliateUrl)) return fail(`affiliate_url failed for asin "${asin}"`);

// ── Helpers ───────────────────────────────────────────────────────────────────
const slugify = (s) => String(s||'').toLowerCase().normalize('NFKD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,96);
const round2  = (n) => Math.round(n * 100) / 100;
const clamp   = (n,lo,hi) => Math.max(lo, Math.min(hi, n));
const num     = (v) => { if (v==null) return null; if (typeof v==='number') return v; const m=String(v).replace(/,/g,'').match(/[\d]+(?:\.[\d]+)?/); return m?Number(m[0]):null; };

// ── Creators API field extraction (lowerCamelCase PA-API) ─────────────────────
const info = item.itemInfo || {};
const name = info.title && info.title.displayValue;
if (!name) return fail('Creators item has no itemInfo.title.displayValue');

// price: offersV2.listings[0].price (money.amount | amount | displayString); savingBasis → original
const listing = (item.offersV2 && Array.isArray(item.offersV2.listings)) ? item.offersV2.listings[0] : null;
const priceObj = listing && listing.price;
const money = priceObj && (priceObj.money || priceObj);
let price = money ? (num(money.amount) ?? num(money.value) ?? num(priceObj.displayString) ?? num(priceObj.displayAmount)) : null;
let currency = (money && (money.currencyCode || money.currency)) || 'USD';
const sbMoney = listing && listing.savingBasis && (listing.savingBasis.money || listing.savingBasis);
let originalPrice = sbMoney ? (num(sbMoney.amount) ?? num(sbMoney.value)) : null;
let priceFallback = false;

const priceStore = $getWorkflowStaticData('global');
if (priceStore.priceRunId !== $execution.id) { priceStore.priceRunId = $execution.id; priceStore.firstValidPrice = null; priceStore.firstValidCurrency = null; }
if (price != null) {
  if (priceStore.firstValidPrice == null) { priceStore.firstValidPrice = price; priceStore.firstValidCurrency = currency; }
} else if (priceStore.firstValidPrice != null) {
  price = priceStore.firstValidPrice; currency = priceStore.firstValidCurrency || currency; originalPrice = null; priceFallback = true;
  console.log(JSON.stringify({ event:'price_fallback', asin, borrowedPrice: price, currency, ts: new Date().toISOString() }));
} else {
  return fail('price_unresolved_no_fallback (no offersV2 price in the Creators response)');
}

// discount: explicit savings percentage, else derive from savingBasis
let discountPct = 0;
const savingsPct = priceObj && priceObj.savings && (priceObj.savings.percentage != null ? priceObj.savings.percentage : (priceObj.savings.money && priceObj.savings.money.percentage));
if (!priceFallback && savingsPct != null) discountPct = Math.round(Number(savingsPct));
else if (!priceFallback && price && originalPrice && originalPrice > price) discountPct = Math.round(((originalPrice - price) / originalPrice) * 100);

// ── Brand ─────────────────────────────────────────────────────────────────────
const byline = info.byLineInfo || {};
let brand = (byline.brand && byline.brand.displayValue) || (byline.manufacturer && byline.manufacturer.displayValue);
if (!brand && typeof name === 'string') brand = name.split(/\s+/)[0];
if (!brand) return fail('no brand');

// ── Image (images.primary.large) ──────────────────────────────────────────────
const large = item.images && item.images.primary && item.images.primary.large;
const imageUrl = large && large.url;
if (!imageUrl) return fail('no image URL (Creators images.primary.large)');
const imageDim = (large && (Number(large.width) || Number(large.height))) || 1500;

// ── Rating (REAL — Creators exposes customerReviews) ──────────────────────────
const cr = item.customerReviews || {};
let rating = num(cr.starRating && (cr.starRating.value != null ? cr.starRating.value : cr.starRating));
if (rating == null) rating = num(cr.rating);
rating = Math.round(clamp(Number(rating)||0,0,5)*10)/10;

// ── Features / tags ───────────────────────────────────────────────────────────
const featureBullets = (info.features && Array.isArray(info.features.displayValues)) ? info.features.displayValues : [];
const nodes = item.browseNodeInfo && item.browseNodeInfo.browseNodes;
const tags = Array.isArray(nodes) ? nodes.map(n => n && n.displayName).filter(Boolean) : [];

const shortDesc = String(featureBullets[0] || name).slice(0,200);
const longDesc  = featureBullets.length ? featureBullets.slice(0,6).join('\n\n') : '';

const slug     = `${slugify(name)}-${asin.toLowerCase()}`;
const title    = String(name).slice(0,120);
const imageKey = `products/amazon/${asin}/main.jpg`;

const CURRENCIES = ['USD','GBP','EUR','CAD','AUD'];
if (!CURRENCIES.includes(currency)) currency = 'USD';

console.log(JSON.stringify({ event:'url_validated', asin, affiliate_url: affiliateUrl, priceFallback, rating, discountPct, ts: new Date().toISOString() }));

return [{
  json: {
    valid: true, skipReason: null, priceFallback,
    asin, slug, imageUrl, imageKey, imageDim, imageAlt: title,
    product: {
      slug,
      title,
      brand:                String(brand).slice(0,80),
      short_description:    shortDesc,
      description:          longDesc,
      price:                round2(price),
      original_price:       originalPrice != null ? round2(originalPrice) : null,
      currency,
      discount_percent:     discountPct,
      deal_label:           null,
      affiliate_source:     'amazon',
      amazon_affiliate_tag: affiliateTag,
      affiliate_url:        affiliateUrl,   // clean HTTPS amazon.com/dp/ASIN — tagless
      rating,                              // REAL star rating from Creators customerReviews
      features:             featureBullets.slice(0,10),
      tags,
      pros:                 [],
      cons:                 [],
      subcategory_id:       null,
      seo_title:            null,
      seo_description:      null,
      seo_og_image:         null,
    },
  },
}];

// Log Skipped Item (v3.1) — audit trail for items the workflow skips.
// Reached only on the FALSE branch of 'Is Valid?' (unavailable, no price to borrow,
// no brand, no image, bad URL, etc.). Connects back to Loop Over Items so the run
// continues to the next ASIN instead of terminating.
const item = $input.first().json;
const entry = {
  event:  'item_skipped',
  asin:   item.asin ?? null,
  reason: item.skipReason ?? 'unknown',
  ts:     new Date().toISOString(),
};
console.log(JSON.stringify(entry));
return [{ json: { ...item, _skipped: true, _log: entry } }];

// ── AI Gate Decision ─────────────────────────────────────────────────────────
// Reads the DB check result and the overrideAiFields config flag.
// Sets skipAi=true when all 5 AI fields are already populated AND override is off.
const cfg    = $('Config').first().json;
const norm   = $('Is Valid?').first().json;
const dbRows = $input.all();     // 0 rows = new product, 1 row = existing

const override = cfg.overrideAiFields === true;

let allPopulated = false;
if (dbRows.length > 0) {
  const r = dbRows[0].json;
  allPopulated = r.has_subcategory_id && r.has_pros && r.has_cons && r.has_seo_title && r.has_seo_description;
}

const skipAi = allPopulated && !override;

console.log(JSON.stringify({
  event: 'ai_gate', asin: norm.asin,
  allPopulated, override, skipAi,
  ts: new Date().toISOString(),
}));

return [{ json: { ...norm, skipAi } }];

// ─────────────────────────────────────────────────────────────────────────────
// Build AI Enrichment Request
// Single OpenRouter call for: subcategory name, pros[], cons[], seo_title, seo_description.
// subcategory is sent as a NAME here; resolved to a uuid in Parse & Validate AI Fields.
// ─────────────────────────────────────────────────────────────────────────────
const cfg     = $('Config').first().json;
const norm    = $input.first().json;
const product = norm.product;

// Build the list of available subcategory names for the prompt
const subcatRows = $('Fetch Subcategories').all().map(i => i.json);
const subcatNames = subcatRows
  .filter(r => r?.name)
  .map(r => String(r.name).trim())
  .slice(0, 80);    // cap prompt length

const featureBullets = Array.isArray(product.features) ? product.features : [];
const tags           = Array.isArray(product.tags)     ? product.tags     : [];

const productContext = [
  `Title: ${product.title}`,
  `Brand: ${product.brand}`,
  product.short_description ? `Short description: ${product.short_description}` : null,
  product.description       ? `Full description: ${String(product.description).slice(0,500)}` : null,
  featureBullets.length     ? `Key features:\n${featureBullets.slice(0,8).map(f=>`- ${f}`).join('\n')}` : null,
  tags.length               ? `Category breadcrumbs: ${tags.slice(0,5).join(' > ')}` : null,
  `Price: ${product.currency} ${product.price}`,
  product.original_price    ? `Original price: ${product.currency} ${product.original_price}` : null,
  product.rating            ? `Average rating: ${product.rating}/5` : null,
].filter(Boolean).join('\n');

const subcatSection = subcatNames.length
  ? `Available subcategories (choose the single best fit; use exact spelling):\n${subcatNames.map(n=>`- ${n}`).join('\n')}`
  : 'No subcategory list available — infer the most appropriate retail subcategory name.';

const systemPrompt = [
  'You are a product data enrichment assistant for an affiliate e-commerce site.',
  'Return ONLY this JSON object — no prose, no markdown fences:',
  '{',
  '  "subcategory": "<exact name from the list, or best-fit retail subcategory>",',
  '  "pros": ["<advantage 1>", "<advantage 2>", "<advantage 3>"],',
  '  "cons": ["<disadvantage 1>", "<disadvantage 2>", "<disadvantage 3>"],',
  '  "seo_title": "<keyword-rich title, HARD MAX 60 characters>",',
  '  "seo_description": "<meta description, HARD MAX 160 characters, include primary keyword>"',
  '}',
  '',
  'RULES:',
  '- pros and cons: 3 to 5 items each; each item max 120 characters.',
  '- seo_title: truncate to 60 chars if needed — never exceed.',
  '- seo_description: truncate to 160 chars if needed — never exceed.',
  '- subcategory: use the exact spelling from the provided list when possible.',
  '- Output the JSON object only.',
].join('\n');

const requestBody = {
  model:       cfg.openrouterModel,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: `${subcatSection}\n\nProduct details:\n${productContext}` },
  ],
  temperature: 0.3,
  max_tokens:  700,
};

console.log(JSON.stringify({ event: 'ai_enrichment_built', asin: norm.asin, subcatCount: subcatNames.length, ts: new Date().toISOString() }));

return [{ json: { requestBody, normData: norm } }];

// ─────────────────────────────────────────────────────────────────────────────
// Parse & Validate AI Fields  v2
//
// DB schema truth:
//   pros         → text[]   (stored as jsonb array in payload, cast in upsert)
//   cons         → text[]   (same)
//   subcategory_id → uuid   (AI returns a name; we resolve to UUID here)
//   seo_title    → text     (enforced ≤ 60 chars)
//   seo_description → text  (enforced ≤ 160 chars)
// ─────────────────────────────────────────────────────────────────────────────
const SEO_TITLE_MAX      = 60;
const SEO_DESC_MAX       = 160;
const ITEM_MAX           = 120;   // max chars per pros/cons bullet
const MIN_ITEMS          = 3;
const MAX_ITEMS          = 5;

const aiRes  = $input.first().json;
const req    = $('Build AI Enrichment Request').first().json;
const norm   = req.normData;

// ── Subcategory lookup table (name → uuid) ────────────────────────────────────
const subcatRows = $('Fetch Subcategories').all().map(i => i.json);
const nameToSubcatId = new Map();
for (const r of subcatRows) {
  if (r?.id && r?.name) nameToSubcatId.set(String(r.name).trim().toLowerCase(), r.id);
}

function resolveSubcatId(aiName) {
  if (!aiName || typeof aiName !== 'string') return null;
  const key = aiName.trim().toLowerCase();
  // 1. Exact match (case-insensitive)
  if (nameToSubcatId.has(key)) return nameToSubcatId.get(key);
  // 2. Starts-with match (handles minor suffix differences)
  for (const [k, id] of nameToSubcatId) {
    if (k.startsWith(key) || key.startsWith(k)) return id;
  }
  // 3. Contains match as last resort
  for (const [k, id] of nameToSubcatId) {
    if (k.includes(key) || key.includes(k)) return id;
  }
  return null;   // no match → column stays null
}

// ── Rate-limit guard ──────────────────────────────────────────────────────────
if (aiRes?.error?.code === 429 || aiRes?.statusCode === 429) {
  console.warn(JSON.stringify({ event:'ai_rate_limited', asin: norm.asin, ts: new Date().toISOString() }));
  return [{ json: { ...norm, _aiStatus: 'rate_limited' } }];
}

// ── HTTP / API error guard ────────────────────────────────────────────────────
// neverError:true swallows non-2xx responses; surface them loudly instead of
// silently emitting empty AI fields. A 401 here = the OpenRouter credential is
// not selected on the 'Call OpenRouter (AI Enrichment)' node (see n8n/README.md).
if (aiRes && aiRes.error) {
  const code = aiRes.error.code ?? 'unknown';
  console.warn(JSON.stringify({ event:'ai_http_error', asin: norm.asin, code, message: String(aiRes.error.message || '').slice(0,200), ts: new Date().toISOString() }));
  return [{ json: { ...norm, _aiStatus: `http_error_${code}` } }];
}

// ── Extract raw content string ────────────────────────────────────────────────
function getContent(r) {
  const str = r?.choices?.[0]?.message?.content;
  if (typeof str === 'string' && str.trim()) return str;
  if (Array.isArray(str)) return str.filter(x=>x?.type==='text').map(x=>x.text).join('');
  return r?.choices?.[0]?.text ?? null;
}

// ── Loose JSON parser ─────────────────────────────────────────────────────────
function parseLoose(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch {}
  const f = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (f) { try { return JSON.parse(f[1]); } catch {} }
  const a = text.indexOf('{'), b = text.lastIndexOf('}');
  if (a >= 0 && b > a) { try { return JSON.parse(text.slice(a, b+1)); } catch {} }
  return null;
}

// ── Sanitise helpers ──────────────────────────────────────────────────────────
// Remove ASCII control chars (except tab/newline), trim.
const sanitise = (s) => String(s || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '').trim();
const trunc    = (s, n) => sanitise(s).slice(0, n);

// Validate + sanitise a text[] array field.
// Returns an array of strings, clipped to [MIN_ITEMS..MAX_ITEMS] items.
function normArray(arr) {
  if (!Array.isArray(arr)) return [];
  return arr
    .map(x => trunc(String(x ?? ''), ITEM_MAX))
    .filter(Boolean)
    .slice(0, MAX_ITEMS);
}

// ── Parse response ────────────────────────────────────────────────────────────
const content = getContent(aiRes);
const parsed  = parseLoose(content);

let aiStatus        = 'success';
let subcategoryName = null;
let subcategory_id  = null;
let pros            = [];
let cons            = [];
let seo_title       = null;
let seo_description = null;

if (!parsed) {
  aiStatus = 'parse_failed';
  console.warn(JSON.stringify({ event:'ai_parse_failed', asin: norm.asin, head: String(content||'').slice(0,300), ts: new Date().toISOString() }));
} else {
  // subcategory: resolve name → UUID
  subcategoryName = sanitise(parsed.subcategory || '');
  subcategory_id  = resolveSubcatId(subcategoryName) ?? null;
  if (!subcategory_id && subcategoryName) aiStatus = 'subcategory_unresolved';

  // pros / cons → text[] (stored as JSON arrays in payload, converted to pg text[] in upsert)
  pros = normArray(parsed.pros);
  cons = normArray(parsed.cons);
  if (pros.length < MIN_ITEMS) aiStatus = aiStatus === 'success' ? 'partial_pros' : aiStatus;
  if (cons.length < MIN_ITEMS) aiStatus = aiStatus === 'success' ? 'partial_cons' : aiStatus;

  // seo fields
  seo_title       = trunc(parsed.seo_title       || '', SEO_TITLE_MAX)  || null;
  seo_description = trunc(parsed.seo_description || '', SEO_DESC_MAX)   || null;
  if (!seo_title)       aiStatus = 'missing_seo_title';
  if (!seo_description) aiStatus = aiStatus === 'success' ? 'missing_seo_description' : aiStatus;
}

console.log(JSON.stringify({
  event:           'ai_enrichment_parsed',
  asin:            norm.asin,
  aiStatus,
  subcategoryName,
  subcategory_id,
  seo_title_len:   seo_title?.length ?? 0,
  seo_desc_len:    seo_description?.length ?? 0,
  pros_count:      pros.length,
  cons_count:      cons.length,
  ts:              new Date().toISOString(),
}));

return [{
  json: {
    ...norm,
    product: {
      ...norm.product,
      subcategory_id,    // uuid | null
      pros,              // string[] (maps to text[] via jsonb_array_elements_text in upsert)
      cons,              // string[] (same)
      seo_title,         // string | null — max 60
      seo_description,   // string | null — max 160
    },
    _aiStatus: aiStatus,
  },
}];

// Bypass branch — AI fields already populated in DB; pass norm data unchanged.
const norm = $input.first().json;
