// Build OpenRouter category classification request — unchanged from v1 logic.
const cfg = $('Config').first().json;
const categoriesRows = $('Fetch Categories').all().map(i => i.json);
const norm = $input.first().json;

if (categoriesRows.length === 0) {
  return [{ json: { skip: true, reason: 'no_categories_in_db', labelMap: [], normPassthrough: norm } }];
}

const labelToId = new Map();
const lines = [];
for (const c of categoriesRows) {
  if (!c?.id || !c?.name) continue;
  let label = String(c.name).trim();
  let suffix = 2;
  while (labelToId.has(label)) label = `${c.name} #${suffix++}`;
  labelToId.set(label, c.id);
  const desc = c.description ? ` — ${String(c.description).slice(0,140)}` : '';
  lines.push(`- ${label}${desc}`);
}

const product = norm.product;
const productContext = [
  `Title: ${product.title}`,
  `Brand: ${product.brand}`,
  product.short_description ? `Description: ${product.short_description}` : null,
  product.tags?.length      ? `Tags: ${product.tags.slice(0,8).join(', ')}` : null,
  product.features?.length  ? `Key features: ${product.features.slice(0,3).join('; ')}` : null,
].filter(Boolean).join('\n');

const systemPrompt = [
  'You are a product categorization assistant for an affiliate deals website.',
  'Given a product and a list of categories, return your TOP THREE most likely categories ranked by fit.',
  'RESPOND WITH ONLY THIS JSON OBJECT — no prose, no code fences:',
  '{"rankings":[{"category":"<exact name from list>","confidence":<0.0-1.0>,"reasoning":"<one short sentence>"}]}',
  'RULES:',
  '- "category" MUST be copied verbatim from the list (text after "- ", before any —).',
  '- Up to 3 rankings, descending confidence. Minimum 1.',
  '- If NO category fits return {"rankings":[]}.',
  '- Output JSON only.',
].join('\n');

const requestBody = {
  model:    cfg.openrouterModel,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: `Available categories:\n${lines.join('\n')}\n\nProduct:\n${productContext}` },
  ],
  temperature: 0,
  max_tokens:  400,
};

return [{ json: { requestBody, labelMap: Array.from(labelToId.entries()), normPassthrough: norm } }];

// Resolve OpenRouter classifier response → category_id uuid.
const cfg = $('Config').first().json;
const res = $input.first().json;
const req = $('Build Classifier Request').first().json;
const norm = req.normPassthrough;

const threshold = Number(cfg.classifierConfidenceThreshold) || 0.6;
const labelToId = new Map(Array.isArray(req?.labelMap) ? req.labelMap : []);

function extractContent(r) {
  if (!r || typeof r !== 'object') return { content: null, shape: `non-object:${typeof r}` };
  const str = r?.choices?.[0]?.message?.content;
  if (typeof str === 'string' && str.trim()) return { content: str, shape: 'string' };
  if (Array.isArray(str)) {
    const t = str.filter(x=>x?.type==='text').map(x=>x.text).join('');
    if (t.trim()) return { content: t, shape: 'parts' };
  }
  const legacy = r?.choices?.[0]?.text;
  if (typeof legacy === 'string' && legacy.trim()) return { content: legacy, shape: 'legacy' };
  return { content: null, shape: `keys=[${Object.keys(r).join(',')}] err=${JSON.stringify(r?.error??null).slice(0,200)}` };
}

function parseLoose(text) {
  if (typeof text !== 'string') return { value: null, how: 'no-text' };
  try { return { value: JSON.parse(text), how: 'direct' }; } catch {}
  const f = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (f) { try { return { value: JSON.parse(f[1]), how: 'fenced' }; } catch {} }
  const a = text.indexOf('{'), b = text.lastIndexOf('}');
  if (a >= 0 && b > a) { try { return { value: JSON.parse(text.slice(a, b+1)), how: 'substr' }; } catch {} }
  return { value: null, how: 'failed' };
}

function resolve() {
  if (res?.skip)  return { id: cfg.defaultCategoryId, status: `fallback_${res.reason}`,           confidence: 0, note: 'no categories' };
  if (res?.error) return { id: cfg.defaultCategoryId, status: 'fallback_api_error',               confidence: 0, note: String(res.error?.message||'') };
  const { content, shape } = extractContent(res);
  if (!content)   return { id: cfg.defaultCategoryId, status: 'fallback_empty_response',          confidence: 0, note: shape };
  const { value: parsed, how } = parseLoose(content);
  if (!parsed)    return { id: cfg.defaultCategoryId, status: 'fallback_parse_error',             confidence: 0, note: `${how}: ${content.slice(0,120)}` };
  const rankings = Array.isArray(parsed?.rankings) ? parsed.rankings : [];
  if (!rankings.length) return { id: cfg.defaultCategoryId, status: 'fallback_no_rankings',      confidence: 0, note: `parse:${how}` };
  const missed = [];
  for (let i = 0; i < rankings.length; i++) {
    const cand  = rankings[i];
    const label = cand?.category ?? cand?.categoryId;
    const conf  = Number(cand?.confidence);
    if (!label || typeof label !== 'string') { missed.push(`r${i+1}:missing`); continue; }
    const realId = labelToId.get(label.trim());
    if (!realId) { missed.push(`r${i+1}:"${label}"`); continue; }
    if (!Number.isFinite(conf) || conf < threshold) {
      return { id: cfg.defaultCategoryId, status: 'fallback_low_confidence', confidence: conf||0, note: `"${label}" conf=${conf}<${threshold}` };
    }
    return { id: realId, status: i === 0 ? 'classified' : `fallback_rank_${i+1}`, confidence: conf, note: `"${label}"→${realId}` };
  }
  return { id: cfg.defaultCategoryId, status: 'fallback_hallucinated', confidence: 0, note: `all invalid:[${missed.join(',')}]` };
}

const r = resolve();
console.log(JSON.stringify({ event:'category_resolved', asin: norm.asin, status: r.status, confidence: r.confidence, note: r.note, ts: new Date().toISOString() }));

return [{
  json: {
    ...norm,
    product: { ...norm.product, category_id: r.id },
    _classifier: { status: r.status, confidence: r.confidence, note: r.note },
  },
}];

